<?php require_once __DIR__.'/../../middleware/bootstrap.php';$d=input();$st=db()->prepare('select * from users where email=?');$st->execute([clean($d['email']??'')]);$u=$st->fetch();if(!$u||!password_verify($d['password']??'',$u['password_hash']))out(['error'=>'Invalid credentials'],401);out(['token'=>jwt($u['id']),'user'=>['id'=>$u['id'],'email'=>$u['email'],'name'=>$u['name'],'role_id'=>$u['role_id']]]);
